-- CareMetric Train production MVP schema for Supabase/Postgres.
-- Original LMS/compliance schema. Enable RLS in Supabase and adapt policies per deployment.
create extension if not exists "pgcrypto";
create type app_role as enum ('super_admin','organization_admin','facility_admin','instructor','learner','auditor');
create type user_status as enum ('active','inactive','pending','terminated');
create type assignment_status as enum ('not_started','in_progress','completed','overdue','failed','waived');
create type approval_status as enum ('pending','approved','rejected');
create table if not exists organizations (id uuid primary key default gen_random_uuid(), name text not null, subscription_status text default 'trial', package_name text default 'Compliance Plus', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists facilities (id uuid primary key default gen_random_uuid(), organization_id uuid not null references organizations(id), name text not null, address text, active boolean default true, created_at timestamptz default now());
create table if not exists profiles (id uuid primary key references auth.users(id), organization_id uuid references organizations(id), first_name text, last_name text, email text unique, status user_status default 'pending', last_login_at timestamptz, created_at timestamptz default now());
create table if not exists user_roles (id uuid primary key default gen_random_uuid(), user_id uuid references profiles(id), organization_id uuid references organizations(id), facility_id uuid references facilities(id), role app_role not null, unique(user_id, organization_id, facility_id, role));
create table if not exists staff_profiles (id uuid primary key default gen_random_uuid(), organization_id uuid not null references organizations(id), facility_id uuid references facilities(id), profile_id uuid references profiles(id), first_name text not null, last_name text not null, email text, phone text, job_title text, staff_category text, hire_date date, employment_status user_status default 'active', supervisor_id uuid, medication_certification_date date, medication_renewal_date date, is_administrator boolean default false, is_direct_care boolean default true, notes text, created_at timestamptz default now());
create table if not exists courses (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), facility_id uuid references facilities(id), title text not null, description text, category text, target_roles text[], estimated_minutes int, credit_hours numeric(5,2), course_type text, required boolean default true, active boolean default true, renewal_period_days int, certificate_eligible boolean default true, tags text[], regulatory_topics text[], author_id uuid references profiles(id), last_reviewed_at date, created_at timestamptz default now());
create table if not exists course_versions (id uuid primary key default gen_random_uuid(), course_id uuid references courses(id), version_number text not null, status text default 'draft', published_at timestamptz, created_by uuid references profiles(id), created_at timestamptz default now());
create table if not exists course_blocks (id uuid primary key default gen_random_uuid(), course_version_id uuid references course_versions(id), block_type text not null, title text, content jsonb default '{}', sort_order int default 0);
create table if not exists quizzes (id uuid primary key default gen_random_uuid(), course_version_id uuid references course_versions(id), passing_score int default 80, retake_limit int default 3, randomize_questions boolean default true, show_correct_answers boolean default false);
create table if not exists quiz_questions (id uuid primary key default gen_random_uuid(), quiz_id uuid references quizzes(id), question_type text not null, prompt text not null, sort_order int default 0);
create table if not exists quiz_answers (id uuid primary key default gen_random_uuid(), question_id uuid references quiz_questions(id), answer_text text not null, is_correct boolean default false);
create table if not exists course_assignments (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), facility_id uuid references facilities(id), course_id uuid references courses(id), course_version_id uuid references course_versions(id), staff_profile_id uuid references staff_profiles(id), assigned_by uuid references profiles(id), due_date date, status assignment_status default 'not_started', waiver_reason text, created_at timestamptz default now());
create table if not exists course_progress (id uuid primary key default gen_random_uuid(), assignment_id uuid references course_assignments(id), staff_profile_id uuid references staff_profiles(id), started_at timestamptz, completed_at timestamptz, percent_complete int default 0);
create table if not exists quiz_attempts (id uuid primary key default gen_random_uuid(), assignment_id uuid references course_assignments(id), quiz_id uuid references quizzes(id), staff_profile_id uuid references staff_profiles(id), score int, passed boolean, submitted_at timestamptz default now());
create table if not exists quiz_attempt_answers (id uuid primary key default gen_random_uuid(), attempt_id uuid references quiz_attempts(id), question_id uuid references quiz_questions(id), selected_answer_ids uuid[], is_correct boolean);
create table if not exists training_plans (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), name text not null, description text, target_roles text[], active boolean default true);
create table if not exists training_plan_items (id uuid primary key default gen_random_uuid(), training_plan_id uuid references training_plans(id), course_id uuid references courses(id), due_days_after_hire int, renewal_interval_days int);
create table if not exists compliance_requirements (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), name text not null, category text, required_roles text[], required_hours numeric(5,2), renewal_period_days int, due_date_rule text, accepted_evidence_types text[], external_certificate_allowed boolean default true, admin_approval_required boolean default false, notes text, citation text, active boolean default true);
create table if not exists compliance_requirement_courses (requirement_id uuid references compliance_requirements(id), course_id uuid references courses(id), primary key(requirement_id, course_id));
create table if not exists staff_compliance_status (id uuid primary key default gen_random_uuid(), staff_profile_id uuid references staff_profiles(id), requirement_id uuid references compliance_requirements(id), status text, hours_completed numeric(5,2), due_date date, expiration_date date, evidence_count int default 0, calculated_at timestamptz default now());
create table if not exists medication_certifications (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), facility_id uuid references facilities(id), staff_profile_id uuid references staff_profiles(id), original_certification_date date, annual_renewal_date date, expiration_date date, trainer_observer text, certificate_file_id uuid, observation_file_id uuid, status text, reminder_days int default 30, notes text);
create table if not exists competency_templates (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), name text not null, category text, active boolean default true);
create table if not exists competency_template_items (id uuid primary key default gen_random_uuid(), template_id uuid references competency_templates(id), item_text text not null, sort_order int default 0);
create table if not exists competency_records (id uuid primary key default gen_random_uuid(), template_id uuid references competency_templates(id), staff_profile_id uuid references staff_profiles(id), observed_by uuid references profiles(id), observed_at date, electronic_signature text, re_observation_due_date date, attachment_file_id uuid, status text);
create table if not exists competency_record_items (id uuid primary key default gen_random_uuid(), record_id uuid references competency_records(id), template_item_id uuid references competency_template_items(id), result text, comments text);
create table if not exists inservice_sessions (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), facility_id uuid references facilities(id), title text not null, instructor_id uuid references profiles(id), starts_at timestamptz, topic text, compliance_requirement_id uuid references compliance_requirements(id), duration_hours numeric(5,2), signin_sheet_file_id uuid);
create table if not exists inservice_attendees (id uuid primary key default gen_random_uuid(), session_id uuid references inservice_sessions(id), staff_profile_id uuid references staff_profiles(id), attended boolean default false, completed_at timestamptz);
create table if not exists external_training_records (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), staff_profile_id uuid references staff_profiles(id), certificate_name text, issuing_organization text, completed_at date, expiration_date date, hours numeric(5,2), compliance_requirement_id uuid references compliance_requirements(id), uploaded_file_id uuid, approval_status approval_status default 'pending', reviewer_id uuid references profiles(id), review_comments text);
create table if not exists certificates (id uuid primary key default gen_random_uuid(), certificate_id text unique not null, staff_profile_id uuid references staff_profiles(id), course_id uuid references courses(id), course_version_id uuid references course_versions(id), completed_at date, credit_hours numeric(5,2), verification_url text, pdf_file_id uuid);
create table if not exists notifications (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), user_id uuid references profiles(id), type text, title text, body text, read_at timestamptz, email_payload jsonb, created_at timestamptz default now());
create table if not exists reports (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), facility_id uuid references facilities(id), report_type text, parameters jsonb, output_format text, file_id uuid, generated_by uuid references profiles(id), created_at timestamptz default now());
create table if not exists compliance_binder_exports (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), facility_id uuid references facilities(id), date_range daterange, sections text[], staff_ids uuid[], output_format text, file_id uuid, created_by uuid references profiles(id), created_at timestamptz default now());
create table if not exists packages (id uuid primary key default gen_random_uuid(), name text unique not null, learner_limit int, facility_limit int, features jsonb default '{}'::jsonb);
create table if not exists subscriptions (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), package_id uuid references packages(id), status text, trial_ends_at date, current_period_ends_at date);
create table if not exists uploaded_files (id uuid primary key default gen_random_uuid(), organization_id uuid references organizations(id), facility_id uuid references facilities(id), bucket text, path text, original_name text, content_type text, uploaded_by uuid references profiles(id), created_at timestamptz default now());
create table if not exists audit_logs (id uuid primary key default gen_random_uuid(), actor_user_id uuid references profiles(id), organization_id uuid references organizations(id), facility_id uuid references facilities(id), action text not null, entity_type text, entity_id uuid, metadata jsonb default '{}', created_at timestamptz default now());
create table if not exists organization_settings (organization_id uuid primary key references organizations(id), logo_file_id uuid, primary_color text default '#0f766e', accent_color text default '#06b6d4', notification_settings jsonb default '{}', certificate_template jsonb default '{}');
create table if not exists facility_settings (facility_id uuid primary key references facilities(id), settings jsonb default '{}');
create index if not exists idx_staff_org_facility on staff_profiles(organization_id, facility_id);
create index if not exists idx_assignments_staff_status on course_assignments(staff_profile_id, status, due_date);
create index if not exists idx_audit_org_created on audit_logs(organization_id, created_at desc);
alter table organizations enable row level security; alter table facilities enable row level security; alter table profiles enable row level security; alter table staff_profiles enable row level security; alter table courses enable row level security; alter table course_assignments enable row level security; alter table audit_logs enable row level security;
